@@ -178,7 +178,9 @@ ASX_API void asx_evidence_sink_reset(asx_evidence_sink *sink);
  * ------------------------------------------------------------------- */

 /* Run inspection and automatically record findings to an evidence sink.
- * Records one entry per subsystem with appropriate severity. */
+ * Records one entry per subsystem with appropriate severity.
+ * Returns ASX_E_RESOURCE_EXHAUSTED if the sink cannot hold the full result set.
+ * This operation is failure-atomic: on exhaustion, the sink is unchanged. */
 ASX_API ASX_MUST_USE asx_status asx_inspect_to_evidence(const asx_runtime *rt,
                                                         asx_evidence_sink *sink);

@@ -231,15 +231,29 @@ void asx_evidence_sink_reset(asx_evidence_sink *sink) {
 /* Inspect-to-evidence pipeline                                        */
 /* ------------------------------------------------------------------ */

+static uint32_t inspect_evidence_entry_count(const asx_inspection_report *rpt) {
+    uint32_t count = 7u; /* runtime, regions, tasks, obligations, io, blocking, trace */
+
+    if (rpt->any_poisoned) count++;
+    if (rpt->ghosts.violation_count > 0u) count++;
+
+    return count;
+}
+
 asx_status asx_inspect_to_evidence(const asx_runtime *rt, asx_evidence_sink *sink) {
     asx_inspection_report rpt;
     asx_status st;
+    uint32_t needed;

     if (rt == NULL || sink == NULL) return ASX_E_INVALID_ARGUMENT;

     st = asx_inspect(rt, &rpt);
     if (st != ASX_OK) return st;

+    needed = inspect_evidence_entry_count(&rpt);
+    if (sink->count > ASX_EVIDENCE_SINK_CAPACITY) return ASX_E_INVALID_ARGUMENT;
+    if (needed > ASX_EVIDENCE_SINK_CAPACITY - sink->count) return ASX_E_RESOURCE_EXHAUSTED;
+
     /* Runtime initialization */
     st =
         asx_evidence_record(sink, "inspect:runtime",

@@ -268,8 +268,17 @@ int asx_overload_catalog_decision_consistent(const asx_overload_catalog_entry *e
     /* Mode must match */
     if (decision->mode != entry->mode) return 0;

-    /* When not triggered, admit_status must be OK */
-    if (!decision->triggered) { return decision->admit_status == ASX_OK; }
+    /* When not triggered, load must stay below threshold and no shedding occurs. */
+    if (!decision->triggered) {
+        return decision->load_pct < entry->threshold_pct && decision->shed_count == 0u &&
+               decision->admit_status == ASX_OK;
+    }
+
+    /* Zero-capacity evaluation reports a fail-closed exhaustion sentinel
+     * before mode-specific overload handling, so all catalog modes accept it. */
+    if (decision->admit_status == ASX_E_RESOURCE_EXHAUSTED) {
+        return decision->load_pct == 100u && decision->shed_count == 0u;
+    }

     /* When triggered, check mode-specific outcomes */
     switch (entry->mode) {

@@ -411,6 +411,27 @@ static void test_inspect_to_evidence_null_args(void) {
     ASSERT(asx_inspect_to_evidence(&rt, NULL) == ASX_E_INVALID_ARGUMENT, "null sink");
 }

+static void test_inspect_to_evidence_exhaustion_is_failure_atomic(void) {
+    asx_runtime rt;
+    asx_evidence_sink sink;
+    asx_evidence_sink before;
+    uint32_t i;
+
+    MUST_OK(asx_runtime_init_default(&rt));
+    asx_evidence_sink_init(&sink);
+
+    for (i = 0; i < ASX_EVIDENCE_SINK_CAPACITY - 6u; i++) {
+        MUST_OK(asx_evidence_record(&sink, "prefill", ASX_EVIDENCE_INFO, "entry", i));
+    }
+    before = sink;
+
+    ASSERT(asx_inspect_to_evidence(&rt, &sink) == ASX_E_RESOURCE_EXHAUSTED,
+           "inspect_to_evidence rejects partial-capacity sink");
+    ASSERT(memcmp(&sink, &before, sizeof(sink)) == 0, "sink unchanged on exhaustion");
+
+    asx_runtime_shutdown(&rt);
+}
+
 /* ================================================================== */
 /* End-to-end: diagnostic context + inspection + evidence             */
 /* ================================================================== */
